            a = json.loads(line)
            title = (a.get('title') or '').lower()
            content = (a.get('content') or '')[:10000].lower()
            if 'champions league' in content and ('bracket' in content or 'knockout path' in content or 'pathway' in content or 'route to the final' in content):
